// Initialize the Express app using const app = require('express')().listen(3000, () => { console.log('Server listening on port 3000'); });
// Define the middleware route using app.use('/hello/:name', (req, res) => { var name = req.params.name; if (name === 'John') { res.send('Hello ' + name + '!'); } else { res.status(404).send('Not Found'); } });
